sql:
SELECT COUNT(*) AS self_employed_count
FROM alumni
WHERE present_status = 'self-employed';

SELECT alumni_id
FROM event_registrations
WHERE attendance_status = 'not attended';

SELECT name
FROM alumni
WHERE present_status = 'Self Employed';

external_knowledge:
- 'most active alumni' refers to those with the highest combined total of posts and comments; 
- 'past month' means the period from the current date to 30 days prior to the current date; 
- 'prominent contributors' refers to alumni with the highest total activity; 
- 'multitude of voices' refers to the large number of posts and comments made by the alumni.

sql:
SELECT present_status
FROM alumni
WHERE department_id = (SELECT department_id FROM departments WHERE department_name = 'Computer Science and Engineering');

SELECT forum_name
FROM discussion_forums
WHERE forum_id = 0;

SELECT department_id, COUNT(*) AS total_alumni
FROM alumni
GROUP BY department_id;

SELECT event_name 
FROM events 
ORDER BY event_date ASC;
